window.__QUIZ_DATA__=[{"id":"theory>Mathematics>1999>PART I>1>a","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"a","group":"FINAL","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Simplify(425)-1/2x24\u00f7(152)-2","images":[],"marking_scheme":"(425)-1/2x24\u00f7(152)-2  Recall(ab)-n=(bn)n  \u2234(425)-1/2=(254)1/2and(152)-2=(215)2  \u2234(425)-1/2x24\u00f7(152)-2=(254)1/2x24\u00f7(215)2  Applying bodmas   =(254)1/2x(24\u00f7(215)2)=52x24x15222  =52x2422x152=52x24 - 2x152  =52x22x152=52x4x225=5x2x225  =10x225=2250","marks":"4","difficulty":"3"},{"id":"theory>Mathematics>1999>PART I>1>b","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"b","group":"FINAL","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Evaluatelog535+3log5152-log5818","images":[],"marking_scheme":"log535+3log5152-log5818  Recallnlogax=logaxn  =log535+log5(152)3 -log5818  =log5(35x15323\u00f7818)=log5(35x1538x881)  =log5(35x151x151x151x181)=log5(5x5)=log552  =2log55=2(sincelogaa=1)","marks":"4","difficulty":"3"},{"id":"theory>Mathematics>1999>PART I>2>a>i","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"i","group":"","topic":"NUMBER AND NUMERATION : SETS","question":"If \u03b5 is the set {1, 2, 3, ..., 19, 20} and A, B and C are subsets of \u03b5 such that A = {multiples of 5}; B = {multiples of 4} and C = {multiples of 3}.    List the elements of A","images":[],"marking_scheme":"A = {5, 10, 15, 20}","marks":"1","difficulty":"1"},{"id":"theory>Mathematics>1999>PART I>2>a>ii","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"ii","group":"","topic":"NUMBER AND NUMERATION : SETS","question":"If \u03b5 is the set {1, 2, 3, ..., 19, 20} and A, B and C are subsets of \u03b5 such that A = {multiples of 5}; B = {multiples of 4} and C = {multiples of 3}.  List the elements of B","images":[],"marking_scheme":"B = {4, 8, 12, 16, 20}","marks":"1","difficulty":"1"},{"id":"theory>Mathematics>1999>PART I>2>a>iii","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"iii","group":"","topic":"NUMBER AND NUMERATION : SETS","question":"If \u03b5 is the set {1, 2, 3, ..., 19, 20} and A, B and C are subsets of \u03b5 such that A = {multiples of 5}; B = {multiples of 4} and C = {multiples of 3}.  List the elements of C","images":[],"marking_scheme":"C = {3, 6, 9, 12, 15, 18}","marks":"1","difficulty":"1"},{"id":"theory>Mathematics>1999>PART I>2>b>i","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"i","group":"","topic":"NUMBER AND NUMERATION : SETS","question":"If \u03b5 is the set {1, 2, 3, ..., 19, 20} and A, B and C are subsets of \u03b5 such that A = {multiples of 5}; B = {multiples of 4} and C = {multiples of 3}.  Find: A \u22c2 B","images":[],"marking_scheme":"A \u22c2 B = Elements common to sets A and B  \u2234 A \u22c2 B = {20}","marks":"1","difficulty":"2"},{"id":"theory>Mathematics>1999>PART I>2>b>ii","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"ii","group":"","topic":"NUMBER AND NUMERATION : SETS","question":"If \u03b5 is the set {1, 2, 3, ..., 19, 20} and A, B and C are subsets of \u03b5 such that A = {multiples of 5}; B = {multiples of 4} and C = {multiples of 3}.  Find: A \u22c2 C","images":[],"marking_scheme":"A \u22c2 C = Elements common to sets A and B  \u2234 A \u22c2 C = {15}","marks":"1","difficulty":"2"},{"id":"theory>Mathematics>1999>PART I>2>b>iii","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"iii","group":"","topic":"NUMBER AND NUMERATION : SETS","question":"If \u03b5 is the set {1, 2, 3, ..., 19, 20} and A, B and C are subsets of \u03b5 such that A = {multiples of 5}; B = {multiples of 4} and C = {multiples of 3}.  Find: B \u22c3 C","images":[],"marking_scheme":"B \u22c3 C = The combination of elements of set B and set C without repetition.  B \u22c3 C = {3, 4, 6, 8, 9, 12, 15, 16, 18, 20}","marks":"1","difficulty":"2"},{"id":"theory>Mathematics>1999>PART I>2>c","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"c","group":"","topic":"NUMBER AND NUMERATION : SETS","question":"If \u03b5 is the set {1, 2, 3, ..., 19, 20} and A, B and C are subsets of \u03b5 such that A = {multiples of 5}; B = {multiples of 4} and C = {multiples of 3}.  Using your result in (b) show that (A \u22c2 B) \u22c3 (A \u22c2 C) = A \u22c2 (B \u22c3 C)","images":[],"marking_scheme":"To show that (A \u22c2 B) \u22c3 (A \u22c2 C) = A \u22c2 (B \u22c3 C)  A \u22c2 B = {20}  A \u22c2 C = {15}  \u2234 (A \u22c2 B) \u22c3 (A \u22c2 C) = {15, 20}  A = {5, 10, 15, 20}  B \u22c3 C = {3, 4, 6, 8, 9, 12, 15, 16, 18, 20}  \u2234 A \u22c2 (B \u22c3 C) = {15, 20}  From above, it shows that (A \u22c2 B) \u22c3 (A \u22c2 C) = A \u22c2 (B \u22c3 C).","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>1999>PART I>3>a","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"a","group":"FINAL","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"ABC is a triangle, right-angled at C, P is the mid point of  AC , \u2220PBC = 37o and |BC| = 5 cm, calculate:    |AC|, correct to 3 significant figures.","images":["data:image/png;base64,"],"marking_scheme":"Consider \u2206PBC  tan37o=PCBC==>tan37o=PC5  \u2234 PC = 5 tan 37o  Since P is the mid point of AC  \u2234 PC = PA  AC = 2PC ==> AC = 2 x 5 tan 37o  = 10 tan 37o = 10 x 0.7536  = 7.536 = 7.54 (to 3 s.f)","marks":"4","difficulty":"3"},{"id":"theory>Mathematics>1999>PART I>3>b","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"ABC is a triangle, right-angled at C, P is the mid point of  AC , \u2220PBC = 37o and |BC| = 5 cm, calculate:  \u2220PBA","images":["data:image/png;base64,"],"marking_scheme":"Consider \u2206ABC     tan(\u03b1+37)o=ACBC==>tan(\u03b1+37)o=7.5365  tan (\u03b1 + 37)o = 1.5072  \u03b1 + 37o = tan-1(1.5072)  \u03b1 + 37o = 56.44o  \u03b1 = 56.44o - 37o  \u03b1 = 19.44o  \u2234 \u2220PBA = 19.44o","marks":"4","difficulty":"3"},{"id":"theory>Mathematics>1999>PART I>4>a","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"a","group":"FINAL","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"In the diagram, ABCD is a trapezium in which AD||BC and \u2220ABC is a right angle. If |AD| = 15 cm, |BD| = 17 cm and |BC| = 9 cm, calculate:    |AB|","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"Since AD||BC and \u2220ABC = 90o  In \u2206DAB, \u2220A = 90o  \u2234 |AD|2 + |AB|2 = |BD|2  152 + |AB|2 = 172  |AB|2 = 172 - 152  |AB|2 = 289 - 225  |AB|2 = 64  \u2234 |AB| = 8 cm","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>1999>PART I>4>b","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"b","group":"FINAL","topic":"MENSURATION : AREAS","question":"In the diagram, ABCD is a trapezium in which AD||BC and \u2220ABC is a right angle. If |AD| = 15 cm, |BD| = 17 cm and |BC| = 9 cm, calculate:  the area of the triangle BCD","images":["data:image/png;base64,"],"marking_scheme":"AreaoftriangleBCD=12xbasex\u22a5height=12x9xh  Buth=AB=8cm  \u2234Area=12x8x9=4x9=36cm2","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>1999>PART I>4>c","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"c","group":"FINAL","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"In the diagram, ABCD is a trapezium in which AD||BC and \u2220ABC is a right angle. If |AD| = 15 cm, |BD| = 17 cm and |BC| = 9 cm, calculate:  |CD|","images":["data:image/png;base64,"],"marking_scheme":"If BC is produced to Q  \u2234 |CQ| = |AD| - |BC|  \u2234 |CQ| = 15 - 9 = 6 cm  |DQ| = |AB| = 8 cm (opposite sides of a rectangle ADQB)  Using pythagoras theorem:  |CQ|2 + |DQ|2 = |CD|2  62 + 82 = |CD|2  36 + 64 = |CD|2  100 = |CD|2  |CD| = \u221a100  \u2234 |CD| = 10 cm","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>1999>PART I>4>d","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"d","group":"FINAL","topic":"MENSURATION : LENGTHS AND PERIMETERS","question":"In the diagram, ABCD is a trapezium in which AD||BC and \u2220ABC is a right angle. If |AD| = 15 cm, |BD| = 17 cm and |BC| = 9 cm, calculate:  the perimeter of the trapezium","images":["data:image/png;base64,"],"marking_scheme":"Perimeter of trapezium = |AD| + |CD| + |BC| + |AB| = 15 cm + 10 cm + 9 cm + 8 cm = 42 cm","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>1999>PART I>5>a","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"a","group":"FINAL","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"Solve the simultaneous equations 3y - 2x = 21; 4y + 5x = 5","images":[],"marking_scheme":"3y - 2x = 21 ----- (i)  4y + 5x = 5 ----- (ii)  Multiply eqn. (i) by 5 and eqn. (ii) by 2  15y - 10x = 105 ----- (iii)  8y + 10x = 10 ----- (iv) (add)  23y = 115  y=11523  \u2234 y = 5  Substitute 5 for y in eqn. (i)  3(5) - 2x = 21  15 - 2x = 21  15 - 21 = 2x  -6 = 2x  x=-62  \u2234 x = -3  Solution: x = -3, y = 5","marks":"4","difficulty":"3"},{"id":"theory>Mathematics>1999>PART I>5>b>i","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"i","group":"FINAL","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"Six identical cards numbered 1 - 6 are placed face down. A card is to be picked at random. A person wins $60.00 if he picks the card numbered 6. If he picks any of the other cards, he loses $10.00 times the number on the card. Calculate the probability that he:    loses","images":[],"marking_scheme":"No of cards = 6  \u2234 If 6 is picked = wins $60.00  If 5 is picked = loses $10 x 5 = $50  If 4 is picked = loses $10 x 4 = $40  If 3 is picked = loses $10 x 3 = $30  If 2 is picked = loses $10 x 2 = $20  If 1 is picked = loses $10 x 1 = $10  Probabilitythatacardpickedwillendinaloss=No of losesTotal number of chances=56","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>1999>PART I>5>b>ii","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"ii","group":"FINAL","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"Six identical cards numbered 1 - 6 are placed face down. A card is to be picked at random. A person wins $60.00 if he picks the card numbered 6. If he picks any of the other cards, he loses $10.00 times the number on the card. Calculate the probability that he:  loses $20.00","images":[],"marking_scheme":"Probability of losing $20 means chance of picking a card with number 2 on it.  =No of cards with 2 on itTotal number of cards=16","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>1999>PART II>6>a","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"a","group":"FINAL","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The table gives the frequency distribution of marks obtained by a group of students in a test  Marks345678Frequency5x - 1x941  If the mean mark is 5,    calculate the value of x","images":[],"marking_scheme":"Mean=\u2211fx\u2211f= 5  \u2211fx\u2211f=(5 x 5) + 4(x - 1) + 5(x) + 6(9) + 7(4) + 8(1)5 + (x-1) + x + 9 + 4 + 1=5  =15 + 4x - 4 + 5x + 54 + 28 + 85 + 2x + 9 + 4 + 1 - 1=5  =9x + 11 + 54 + 362x + 18= 5  =9x + 1012x + 18=51  =5(2x+18)=9x+101  =10x+90=9x+101  =10x-9x=101-90  \u2234x=11","marks":"5","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>6>b>i","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"i","group":"FINAL","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The table gives the frequency distribution of marks obtained by a group of students in a test  Marks345678Frequency5x - 1x941  If the mean mark is 5,  find the mode","images":[],"marking_scheme":"From the table, mode = 5 because it has the highest frequency","marks":"2","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>6>b>ii","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"ii","group":"FINAL","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The table gives the frequency distribution of marks obtained by a group of students in a test  Marks345678Frequency5x - 1x941  If the mean mark is 5,  find the median of the distribution.","images":[],"marking_scheme":"Medianisthevaluethatoccupythemiddleposition.  \u2211f=5+10+11+9+4+1=40  \u2234Median=n + 12wheren=40  Medianoccursin412thposition=201/2thposition  Fromthetable,201/2thpositioncoincideswithoneofthefives.  \u2234Median=5  OrMedian=20th + 21st2position=5 + 52=5","marks":"3","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>6>c","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"c","group":"FINAL","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"The table gives the frequency distribution of marks obtained by a group of students in a test  Marks345678Frequency5x - 1x941  If the mean mark is 5,  If one of the students is selected at random, find the probability that he scored at least 7 marks.","images":[],"marking_scheme":"At least 7 marks means 7 and above marks.  There are five students in this range.  \u2234Probabilityofatleastascoreof7=540=18","marks":"2","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>7>a>i","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"i","group":"FINAL","topic":"MENSURATION : VOLUMES","question":"A cylindrical pipe is 28 metres long. It's internal radius is 3.5 cm and external radius 5 cm. Calculate:    the volume in cm3, of metal used in making the pipe    [Take \u03c0 = 22/7]","images":["data:image/png;base64,"],"marking_scheme":"Area shaded = \u03c0R2 - \u03c0r2 = \u03c0(R2 - r2)  Where R = 5 cm and r = 3.5 cm  Area = \u03c0(52 - 3.52) = \u03c0(25 - 12.25) = 12.75\u03c0 cm2  height = 28 m = 2800 cm  Volume = Area shaded x height  = 12.75\u03c0 x 2800 cm3  =12.75x227x2800cm3  =785,4007=112,200cm3","marks":"3","difficulty":"2"},{"id":"theory>Mathematics>1999>PART II>7>a>ii","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"ii","group":"FINAL","topic":"MENSURATION : VOLUMES","question":"A cylindrical pipe is 28 metres long. It's internal radius is 3.5 cm and external radius 5 cm. Calculate:  the volume of water in litres that the pipe can hold when full, correct to 1 decimal place.    [Take \u03c0 = 22/7]","images":[],"marking_scheme":"Volumeofwaterthepipecanholdwhenfull=\u03c0r2h  =227x3.5x3.5x2800  =754,6007=107,800cm3  Recall:1000cm3=1litre  \u2234Volumeinlitre=107,8001000=107.8litres","marks":"3","difficulty":"2"},{"id":"theory>Mathematics>1999>PART II>7>b","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"b","group":"","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, MP is a tangent to the circle LMN at M. If the chord LN is parallel to MP, show that the triangle LMN is isosceles.","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"LN||MP; \u2220NMP = \u03b1  \u2234 \u2220NLM = \u03b1 (angle between a chord and a tangent at the point of contact equals angle in the alternate segment)  \u2220LMC = \u2220LNM (angle between a chord and a tangent at the point of contact equals angle in the alternate segment)  If \u2220LMC = \u03b2 and CP||LN  hence \u2220LMC = \u2220MLN (alternate angles)  \u2234 \u03b2 = \u03b1  But \u03b1 and \u03b2 are angles of \u2206LMN  \u2234 \u2206LMN is an isosceles triangle","marks":"6","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>8>a","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"a","group":"FINAL","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"Given that sin (A + B) = sin Acos B + cos AsinB, without using mathematical tables or calculator, evaluate sin 105o, leaving your answer in surd form. (you may use 105o = 60o + 45o)","images":[],"marking_scheme":"sin(A+B)=sinAcosB+cosAsinB  sin105o=sin(60o+45o)  Bysubstituting60oforAand45oforB  sin105o=sin60ocos45o+cos60osin45o  Butsin60o=\u221a32;sin45o=1\u221a2;cos45o=1\u221a2andcos60o=12  sin105o=\u221a32x1\u221a2+12x1\u221a2  =\u221a32\u221a2+12\u221a2=\u221a3 + 12\u221a2  =\u221a3 + 12\u221a2x\u221a2\u221a2(Byrationalisation)  =\u221a2(\u221a3 + 1)4or\u221a6 + \u221a24","marks":"3","difficulty":"2"},{"id":"theory>Mathematics>1999>PART II>8>b","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"b","group":"FINAL","topic":"NUMBER AND NUMERATION : LOGICAL REASONING","question":"The houses on one side of a particular street are assigned odd numbers, starting from 11. If the sum of the numbers is 551, how many houses are there?","images":[],"marking_scheme":"All houses on one side are assigned odd numbers starting from 11  \u2234 Other houses has numbers 13, 15, 17, 19 ... The first is 11.  This conforms to an arithmetic sequency with a = 11; d = 2.  Where a = first term; d = common difference.  Sn = n/2[2a + (n - 1)d]  Sn = sum of all terms; where n = number of houses  551 = n/2[2 x 11 + (n - 1)2]  = 551 x 2 = n(22 + 2n - 2)  = 1102 = n(20 + 2n)  = 1102 = 20n + 2n2  \u2234 2n2 + 20n - 1102 = 0  (n + 29)(n - 19) = 0  Either n + 29 = 0 or n - 19 = 0  \u2234 n = -29 or n = 19  \u2234 Since n represents number of houses, then it can only be positive n = 19. There are 19 houses.","marks":"4","difficulty":"1"},{"id":"theory>Mathematics>1999>PART II>8>c>i","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"i","group":"FINAL","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"The first and third term of a Geometric Progression (G.P) are 2 and 2/9 respectively. Find:    the common ratio","images":[],"marking_scheme":"Tn = arn - 1  T1 = a = 2 ------ (i)  T3 = ar2 = 2/9 ---- (ii)    Divide eqn. (ii) by eqn. (i)  ar2a=2/92  r2 = 1/9    \u2234 r = \u221a1/9 = 1/3","marks":"3","difficulty":"2"},{"id":"theory>Mathematics>1999>PART II>8>c>ii","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"ii","group":"FINAL","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"The first and third term of a Geometric Progression (G.P) are 2 and 2/9 respectively. Find:  the 5th term","images":[],"marking_scheme":"Tn = arn - 1    T5 = 2 x (1/3)5 - 1    = 2 x (1/3)4    = 2 x 1/81    \u2234 T5 = 2/81","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>1999>PART II>9>a","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"a","group":"FINAL","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"In the diagram, a ladder TF, 10 m long is placed against a wall at an angle of 70o to the horizontal.    How high up the wall, correct to the nearest metre does the ladder reach?","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"length of the ladder = 10 m  angle of inclination to the horizon = 70o  height of ladder tip above the ground = x m  From\u2206TQFsin70o=TQTF=x10  x = 10sin 70o = 10 x 0.9397  \u2234 TQ = 9.397 m = 9 m (to the nearest metre)","marks":"5","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>9>b>i","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"i","group":"FINAL","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"In the diagram, a ladder TF, 10 m long is placed against a wall at an angle of 70o to the horizontal.If the foot (F) of the ladder is pulled from the wall to F1 by 1 metre.    How far, correct to 2 significant figures, does the top T, slide down the wall to T1?","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"From\u2206TQFcos70o=QFTF=QF10  QF = 10cos 70o = 10 x 0.3420 = 3.42 m  QF1 = QF + FF1; FF1 = 1m (given)  QF1 = 3.42 + 1 = 4.42 m  T1F1 = 10 m [length of the ladder (given)]     Using pythagoras theorem  |QT1|2 + |QF1|2 = |T1F1|2  4.422 + |QF1|2 = 102  |QF1|2 = 100 - 19.5364  |QF1|2 = 80.4636  \u2234 |QF1| = \u221a80.4636 = 8.97 m  Difference between ladder tips = |QT| - |QT1| = 9.397 - 8.970 = 0.427 m = 0.43 (to 2 s.f)","marks":"4","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>9>b>ii","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"ii","group":"FINAL","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"In the diagram, a ladder TF, 10 m long is placed against a wall at an angle of 70o to the horizontal.Calculate, correct to the nearest degree, \u2220QF1T1.","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"Let \u2220QF1T1 = \u03b1 as shown in the diagram.  \u2234tan\u03b1=QT1QF1=8.974.42=2.0294  \u2234 \u03b1 = tan-1(2.0294)  \u2234 \u03b1 = 63.77o = 64o (to the nearest degree)","marks":"3","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>10>a","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"a","group":"FINAL","topic":"NUMBER AND NUMERATION : VARIATION","question":"The cost of maintaining a school is partly constant and partly varies as the number of pupils. With 50 pupils, the cost is $15,705.00 and with 40 pupils, it is $13,305.00    Find the cost when there are 44 pupils","images":[],"marking_scheme":"Let the cost of maintaining the school = C  C = k + mP where k and m are constants.  P = pupils number  With 50 pupils, cost $15,705.00  \u2234 15,705 = k + 50m ----- (i)  With 40 pupils, cost $13,305.00  \u2234 13,305 = k + 40m ----- (ii)  Subtract eqn. (ii) from eqn. (i)  15,705 = k + 50m ----- (i)  13,305 = k + 40m ----- (ii) (subtract)  2,400 = 10m  \u2234m=240010=240  Substitute 240 for m in eqn. (i)  15,705 = k + 50(240)  15,705 = K + 12,000  \u2234 k = 15,705 - 12,000 = 3,705  Cost of running the school ==> C = 3,705 + 240P  Cost of 44 pupils = 3,705 + 240(44)  = 3,705 + 10,560  \u2234 C = $14,265.00","marks":"6","difficulty":"2"},{"id":"theory>Mathematics>1999>PART II>10>b","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"b","group":"FINAL","topic":"NUMBER AND NUMERATION : VARIATION","question":"The cost of maintaining a school is partly constant and partly varies as the number of pupils. With 50 pupils, the cost is $15,705.00 and with 40 pupils, it is $13,305.00  If the fee per pupil is $360.00, what is the least number of pupils for which the school can be run without loss?","images":[],"marking_scheme":"If each pupil pay $360 and there are P pupils  \u2234 Total fee = $360P  Using the formula C = 3,705 + 240P  For the school to run without loss then,  360P \u2265 3,705 + 240P  = 360P - 240P \u2265 3,705  = 120P \u2265 3,705  =P\u22653,705120  \u2234 P \u2265 30.875  Since 30.875 person is undesirable, then the least possible value of P will be P \u2265 31 pupils.  For the school to run without loss, at least there are 31 pupils.","marks":"6","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>11>a","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"a","group":"","topic":"COORDINATE GEOMETRY OF STRAIGHT LINES : CONCEPT OF THE X-Y PLANE AND COORDINATES OF POINTS ON THE X-Y PLANE","question":"On a graph sheet, using a scale of 2 cm to 2 units on both axes.    Draw the straight line joining points P(-5, 3) and Q(2, 3)","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"1"},{"id":"theory>Mathematics>1999>PART II>11>b","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"b","group":"","topic":"PLANE GEOMETRY : LOCI","question":"On a graph sheet, using a scale of 2 cm to 2 units on both axes.  Construct the locus L of points equidistant from P and Q","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Mathematics>1999>PART II>11>c","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"c","group":"","topic":"PLANE GEOMETRY : CONSTRUCTION","question":"On a graph sheet, using a scale of 2 cm to 2 units on both axes.  By construction, locate points R and S on L, such that PQRS form a rhombus of sides 5 cm.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"4","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>11>d>i","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"i","group":"FINAL","topic":"COORDINATE GEOMETRY OF STRAIGHT LINES : CONCEPT OF THE X-Y PLANE AND COORDINATES OF POINTS ON THE X-Y PLANE","question":"On a graph sheet, using a scale of 2 cm to 2 units on both axes.  Find: coordinates of R and S","images":[],"marking_scheme":"Coordinates of R = (-1.5, -0.4)  Coordinates of S = (-1.5, 6.5)","marks":"1","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>11>d>ii","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"ii","group":"FINAL","topic":"MENSURATION : AREAS","question":"On a graph sheet, using a scale of 2 cm to 2 units on both axes.  Find: area of the rhombus in cm2","images":[],"marking_scheme":"Areaofrhombus=12xproductofdiagonals  =12x7x7cm2=492cm2=24.5cm2","marks":"2","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>12>a","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"a","group":"FINAL","topic":"NUMBER AND NUMERATION : PROFIT AND LOSS","question":"A shop-owner marked a shirt at a price to enable him make a gain of 20%. During a special sales period, the shirt was sold at 10% reduction to a customer for \u20a6864.00. What was the original cost to the shop-owner?","images":[],"marking_scheme":"Lettheoriginalcostbex  \u2234C.P=\u20a6x  Markedprice=\u20a6x+20%of\u20a6x  =\u20a6x+15\u20a6x=\u20a66x5  Reducedprice=10%  =\u20a66x5-10%of\u20a66x5  =\u20a66x5-110x\u20a66x5=\u20a66x5-\u20a66x50  Butreducedprice=\u20a6864.00  \u20a66x5-\u20a66x50=\u20a6864.00  =\u20a660x - 6x50=\u20a6864.00  =\u20a654x50=\u20a6864.00  =\u20a654x=\u20a6864.00x50  =\u20a654x=\u20a643,200.00  \u2234x=\u20a643,200.00\u20a654=\u20a6800.00  Theoriginalcostoftheshirt=\u20a6800.00","marks":"6","difficulty":"2"},{"id":"theory>Mathematics>1999>PART II>12>b>i","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"i","group":"FINAL","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"A rectangular lawn of length (x + 5) metres is (x - 2) metres wide. If the diagonal is (x + 6) metres. Find:    the value of x.","images":["data:image/png;base64,"],"marking_scheme":"Since the lawn is rectangular in shape, each side meets at a right angle.  With the diagram, SQ is the diagonal and the hypotenuse of the right angled triangle SPQ.  Using pythagoras theorem  PS2 + PQ2 = SQ2  (x - 2)2 + (x + 5)2 = (x + 6)2  (x - 2)(x - 2) + (x + 5)(x + 5) = (x + 6)(x + 6)  (x2 - 4x + 4) + (x2 + 10x + 25) = x2 + 12x + 36  2x2 + 6x + 29 = x2 + 12x + 36  2x2 + 6x + 29 - (x2 + 12x + 36) = 0  2x2 + 6x + 29 - x2 - 12x - 36 = 0  x2 - 6x - 7 = 0  Factorise  (x - 7)(x + 1) = 0  x = 7 or x = -1  If x = -1, the side PS = -3 m which is not possible because of the minus sign. We take only the positive value.  \u2234 x = 7 metres.","marks":"4","difficulty":"2"},{"id":"theory>Mathematics>1999>PART II>12>b>ii","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"ii","group":"FINAL","topic":"MENSURATION : AREAS","question":"A rectangular lawn of length (x + 5) metres is (x - 2) metres wide. If the diagonal is (x + 6) metres. Find:  the area of the lawn.","images":[],"marking_scheme":"Area of lawn = length x breadth = (x - 2)(x - 5)  = (x2 + 3x - 10) m2 = 72 + 3(7) - 10  = 49 + 21 - 10 = 60 m2","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>1999>PART II>13>a","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"a","group":"","topic":"TRIGONOMETRY : GRAPHS OF SINE AND COSINE","question":"Copy and complete the following table of values for y = 9cos x + 5 sin x to 1 decimal place.  x0o30o60o90o120o150o180o210oy10.3-0.2-5.3-10.3","images":[],"marking_scheme":"y = 9cos x + 5sin x  When x = 0o, y = 9cos 0o + 5 sin 0o = 9 x 1 + 5 x 0 = 9  When x = 60o, y = 9cos 60o + 5 sin 60o = 9 x 0.5 + 5 x 0.866 = 8.8  When x = 90o, y = 9cos 90o + 5 sin 90o = 9 x 0 + 5 x 1 = 5  When x = 180o, y = 9cos 180o + 5 sin 180o = 9 x -1 + 5 x 0 = -9  x0o30o60o90o120o150o180o210oy9.010.38.85.0-0.2-5.3-9.0-10.3","marks":"3","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>13>b","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"b","group":"","topic":"TRIGONOMETRY : GRAPHS OF SINE AND COSINE","question":"Copy and complete the following table of values for y = 9cos x + 5 sin x to 1 decimal place.  x0o30o60o90o120o150o180o210oy10.3-0.2-5.3-10.3 Using a scale of 2 cm to 30o on the x-axis and 2 cm to 1 unit on the y-axis, draw the graph of y = 9cos x + 5sin x, for 0o \u2264 x \u2264 210o","images":["data:image/png;base64,"],"marking_scheme":"","marks":"5","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>13>c>i","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"i","group":"FINAL","topic":"TRIGONOMETRY : GRAPHS OF SINE AND COSINE","question":"Copy and complete the following table of values for y = 9cos x + 5 sin x to 1 decimal place.  x0o30o60o90o120o150o180o210oy10.3-0.2-5.3-10.3 Use your graph to solve the equation:    9cos x + 5sin x = 0","images":[],"marking_scheme":"9cos x + 5sin x = 0 when y = 0  The solution occurs on x = 119o","marks":"1","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>13>c>ii","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"ii","group":"FINAL","topic":"TRIGONOMETRY : GRAPHS OF SINE AND COSINE","question":"Copy and complete the following table of values for y = 9cos x + 5 sin x to 1 decimal place.  x0o30o60o90o120o150o180o210oy10.3-0.2-5.3-10.3 9cos x + 5sin x = 3.5, correct to the nearest degree.","images":[],"marking_scheme":"9cos x + 5sin x = 3.5 when y = 3.5  The solution occurs on 99o i.e x = 99o","marks":"2","difficulty":"3"},{"id":"theory>Mathematics>1999>PART II>13>d","subject":"Mathematics","year":"1999","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"TRIGONOMETRY : GRAPHS OF SINE AND COSINE","question":"Copy and complete the following table of values for y = 9cos x + 5 sin x to 1 decimal place.  x0o30o60o90o120o150o180o210oy10.3-0.2-5.3-10.3 Find the maximum value of y, correct to one decimal place.","images":[],"marking_scheme":"Maximum value of y is the point where y attained the highest value from the graph  Maximum value of y = 10.3 which occurs at the maximum point","marks":"1","difficulty":"3"}];